class Solution:
    def longestSubsequence(self, nums):
        total = 0
        for x in nums:
            total ^= x
        if total != 0:
            return len(nums)
        # total is zero; try removing each element and take best remaining length with nonzero xor
        best = 0
        n = len(nums)
        for i in range(n):
            rem = total ^ nums[i]
            if rem != 0:
                best = max(best, n - 1)
        return best

